INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d35f0bfc-a880-4f59-aa8f-867b297a21c1', $q$Drag-and-drop Kanban board$q$, $q$Configurable columns with visual work-in-progress limits that highlight overloaded stages.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d35f0bfc-a880-4f59-aa8f-867b297a21c1', $q$Task automation$q$, $q$Automatic actions trigger on events like column moves to reassign, recolor, or update tasks without manual work.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d35f0bfc-a880-4f59-aa8f-867b297a21c1', $q$Search and filter query language$q$, $q$Filter tasks instantly by assignee, category, due date, color, or status using a simple query syntax.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d35f0bfc-a880-4f59-aa8f-867b297a21c1', $q$Subtasks, attachments and Markdown$q$, $q$Break tasks into subtasks, attach files, and write rich descriptions and comments in Markdown.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d35f0bfc-a880-4f59-aa8f-867b297a21c1', $q$LDAP, Active Directory and OAuth2 login$q$, $q$Enterprise-ready authentication against Google, GitHub, GitLab, or an internal directory server.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d35f0bfc-a880-4f59-aa8f-867b297a21c1', $q$REST/JSON-RPC API$q$, $q$Programmatic access for integrations, bots, and custom automation outside the built-in rule engine.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d35f0bfc-a880-4f59-aa8f-867b297a21c1', $q$Plugin ecosystem$q$, $q$Community-built plugins add Slack alerts, webhooks, two-factor auth, and custom themes.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d35f0bfc-a880-4f59-aa8f-867b297a21c1', $q$Multi-language interface$q$, $q$Fully translated UI covering more than 30 languages for global teams.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d35f0bfc-a880-4f59-aa8f-867b297a21c1', $q$Completely free and open source with no feature paywalls$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d35f0bfc-a880-4f59-aa8f-867b297a21c1', $q$Lightweight PHP/SQLite stack is cheap and easy to self-host on modest hardware$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d35f0bfc-a880-4f59-aa8f-867b297a21c1', $q$Simple, distraction-free interface with a low learning curve$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d35f0bfc-a880-4f59-aa8f-867b297a21c1', $q$Full data ownership since nothing is stored on a vendor's servers$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d35f0bfc-a880-4f59-aa8f-867b297a21c1', $q$Extensible via a public API and community plugin ecosystem$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d35f0bfc-a880-4f59-aa8f-867b297a21c1', $q$No official cloud-hosted version from the maintainer, so self-hosting is required for zero cost$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d35f0bfc-a880-4f59-aa8f-867b297a21c1', $q$Development pace has slowed as the project sits in maintenance mode$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d35f0bfc-a880-4f59-aa8f-867b297a21c1', $q$Lacks built-in real-time collaboration features like chat or video calls$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d35f0bfc-a880-4f59-aa8f-867b297a21c1', $q$Mobile experience is a responsive web view rather than dedicated native apps$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d35f0bfc-a880-4f59-aa8f-867b297a21c1', $q$Requires basic server administration knowledge to install, secure, and back up$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d35f0bfc-a880-4f59-aa8f-867b297a21c1', $q$Is Kanboard really free?$q$, $q$Yes. Kanboard is fully open source under the MIT License with no paid tiers, seat limits, or feature gating; you only pay for whatever server you choose to host it on.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d35f0bfc-a880-4f59-aa8f-867b297a21c1', $q$Who created Kanboard?$q$, $q$Kanboard was created by French developer Frederic Guillot and first released in 2014. It is now maintained collaboratively by more than 330 open-source contributors on GitHub.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d35f0bfc-a880-4f59-aa8f-867b297a21c1', $q$Does Kanboard offer a hosted cloud version?$q$, $q$The core project does not sell official cloud hosting, but third-party providers such as Elestio and Stellar Hosted offer managed Kanboard hosting for teams that prefer not to self-host.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d35f0bfc-a880-4f59-aa8f-867b297a21c1', $q$What database does Kanboard use?$q$, $q$It uses SQLite by default for simple, zero-configuration installs, and also supports MySQL and PostgreSQL for larger, multi-user deployments.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d35f0bfc-a880-4f59-aa8f-867b297a21c1', $q$Can Kanboard integrate with other tools?$q$, $q$Yes. It provides a REST/JSON-RPC API, webhook support via plugins, and OAuth2/LDAP authentication, making it straightforward to connect to Slack, Git platforms, and custom scripts.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d35f0bfc-a880-4f59-aa8f-867b297a21c1', $q$How does Kanboard compare to Trello?$q$, $q$Kanboard offers similar drag-and-drop Kanban functionality but is self-hosted, free, and aimed at technical users, whereas Trello is a hosted commercial SaaS product with a broader consumer feature set and paid power-ups.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d35f0bfc-a880-4f59-aa8f-867b297a21c1', $q$Solo developer task tracking$q$, $q$A developer self-hosts Kanboard on a home server or VPS to track personal coding projects without paying for a SaaS subscription.$q$, $q$Independent developers and freelancers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d35f0bfc-a880-4f59-aa8f-867b297a21c1', $q$Small technical team workflow$q$, $q$A small engineering or IT team runs Kanboard behind their VPN to manage sprints and support tickets with LDAP-based single sign-on.$q$, $q$Small software and IT teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d35f0bfc-a880-4f59-aa8f-867b297a21c1', $q$Privacy-conscious project management$q$, $q$Organizations with strict data residency or compliance requirements self-host Kanboard to keep all task data on infrastructure they control.$q$, $q$Privacy-focused organizations and agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d35f0bfc-a880-4f59-aa8f-867b297a21c1', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code under MIT License","Unlimited users and projects","SQLite, MySQL or PostgreSQL support","Docker deployment","Community plugin ecosystem"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d35f0bfc-a880-4f59-aa8f-867b297a21c1', $q$Managed Hosting (third-party)$q$, $q$From approximately $14/month$q$, $q$monthly$q$, NULL, $q$["Provider-managed server and backups","SSL and uptime monitoring","One-click installs","Same free Kanboard software underneath"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d35f0bfc-a880-4f59-aa8f-867b297a21c1', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Kanboard is a lightweight, self-hosted Kanban board built for developers and small teams who want to visualize work without adopting a heavyweight project-management suite. First released in 2014 by French developer Frederic Guillot, it runs on PHP with SQLite as its zero-configuration default database, and can be scaled to MySQL or PostgreSQL for multi-user teams.$q$, $q$Unlike commercial SaaS project trackers, Kanboard has no company behind it selling upgrades or storage tiers. It is released under the MIT License, developed in the open on GitHub with contributions from more than 330 community members, and can be installed on any server you control, giving teams full ownership of their task data.$q$, $q$The project has settled into a stable maintenance rhythm: core functionality is mature and rarely changes, while community pull requests keep the software patched and current. This makes Kanboard a dependable, low-maintenance choice for teams that prioritize stability and self-hosting over a constantly expanding feature list.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d35f0bfc-a880-4f59-aa8f-867b297a21c1', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Kanboard centers on a single, clean drag-and-drop board per project, with configurable columns and enforceable work-in-progress limits that visually flag when a column is overloaded. Tasks support subtasks, file attachments, Markdown-formatted descriptions and comments, categories, colors, due dates, recurring schedules, and basic time tracking.$q$, $q$A built-in query-language search bar lets users filter tasks by assignee, category, due date, color, or status without needing a separate reporting tool, and Gantt and calendar views give a timeline perspective on the same data. Automatic actions let admins define rules that fire on events, such as moving a card to a new column or reassigning it, removing the need for repetitive manual updates.$q$, $q$For integration, Kanboard exposes a REST/JSON-RPC API, supports LDAP/Active Directory and OAuth2 login (Google, GitHub, GitLab), and ships in more than 30 languages. A community plugin ecosystem extends the base app with Slack notifications, webhooks, two-factor authentication, and custom CSS themes.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d35f0bfc-a880-4f59-aa8f-867b297a21c1', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Kanboard itself is entirely free and open source; there is no official paid tier, license fee, or usage cap. Anyone can clone the GitHub repository or pull the official Docker image and run it indefinitely at no cost beyond their own server hosting.$q$, $q$For teams that do not want to manage their own infrastructure, third-party managed-hosting providers such as Elestio and Stellar Hosted offer Kanboard-as-a-service, typically starting around 14 dollars per month, which covers server maintenance, backups, and SSL, while the software license itself remains free.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d35f0bfc-a880-4f59-aa8f-867b297a21c1', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
