INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d35f0bfc-a880-4f59-aa8f-867b297a21c1', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d35f0bfc-a880-4f59-aa8f-867b297a21c1', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Zero-touch Apple deployment$q$, $q$Devices auto-enroll and configure via Apple Automated Device Enrollment the moment they are unboxed.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Blueprints$q$, $q$Reusable configuration templates that apply consistent settings, apps, and policies across groups of devices.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Self Service app catalog$q$, $q$Employees install IT-approved software on demand, cutting down help desk tickets.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Native EDR$q$, $q$Built-in endpoint detection and response for macOS threat monitoring without a separate security agent.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Compliance templates$q$, $q$Pre-built controls mapped to SOC 2, HIPAA, ISO 27001, and CIS benchmarks with automated evidence collection.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Prism fleet visibility$q$, $q$Real-time inventory of installed apps, OS versions, and configuration drift across the whole device fleet.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Vulnerability management$q$, $q$Continuous CVE scanning and prioritized remediation guidance across managed endpoints.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Cross-platform expansion (Iru)$q$, $q$Windows and Android device management and workforce identity, added as part of the Iru platform rebrand.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Purpose-built for Apple deployment with best-in-class zero-touch onboarding$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Combines MDM, EDR, and compliance automation in a single console$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Modern, fast, DevOps-friendly admin interface compared to legacy MDM tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Strong compliance template library speeds up SOC 2 and HIPAA audits$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Backed by significant funding and a fast-growing feature roadmap$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Pricing is not public and requires a sales conversation for every quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Ongoing rebrand to Iru may cause naming and documentation confusion for existing customers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Historically Apple-only, so mixed-fleet organizations needed a second tool until the Iru expansion$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Annual, non-cancellable contracts reduce flexibility for smaller teams$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Per-device costs can add up quickly for organizations with large or mixed hardware fleets$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Is Kandji the same product as Iru?$q$, $q$Yes. Kandji rebranded to Iru starting in late 2025, with the change rolling out across admin, enrollment, and endpoint surfaces through 2026. The underlying platform functionality is unchanged; only branding, some product names, and the scope of supported platforms have expanded.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Does Kandji only support Apple devices?$q$, $q$Kandji was originally Apple-only (Mac, iPhone, iPad), but as part of the Iru rebrand the platform has opened up to Windows and Android device management as well.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$How much does Kandji cost?$q$, $q$Pricing is not published. It is sold via custom, sales-assisted annual contracts, with third-party estimates suggesting roughly 3 to 15 dollars per device per month depending on the modules purchased.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Who founded Kandji?$q$, $q$Kandji was founded in 2018 by Adam Pettit, Wesley Pettit, and Mark Daughters in San Diego, California.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$What is Kandji's main competitor?$q$, $q$Jamf is Kandji's most direct competitor in Apple enterprise management, with Mosyle, Addigy, and Microsoft Intune also frequently compared for mixed-fleet or budget-sensitive deployments.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Does Kandji offer endpoint security, not just device management?$q$, $q$Yes. Kandji includes native EDR for macOS threat detection, continuous vulnerability management, and compliance automation alongside its core MDM functionality.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Apple fleet zero-touch deployment$q$, $q$IT teams ship new Macs and iPhones directly to remote employees, who unbox them and have them auto-enroll with company apps and policies pre-configured.$q$, $q$IT administrators at Apple-heavy companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$SOC 2 and HIPAA compliance evidence$q$, $q$Security teams use pre-built compliance templates and Prism reporting to generate continuous audit-ready evidence for frameworks like SOC 2 and HIPAA.$q$, $q$Security and compliance teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Consolidating MDM and EDR$q$, $q$Organizations replace a separate Apple MDM tool and a separate endpoint security agent with Kandji's combined device management and EDR platform.$q$, $q$Mid-market and enterprise IT/security leaders$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Device Management (MDM)$q$, $q$Custom pricing$q$, $q$annual$q$, NULL, $q$["Zero-touch Apple enrollment","Blueprints and Self Service","Liftoff onboarding","Prism fleet visibility"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Endpoint Security add-on$q$, $q$Custom pricing$q$, $q$annual$q$, NULL, $q$["Native EDR for macOS","Vulnerability management","Threat detection and response"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$Compliance and Identity (Iru)$q$, $q$Custom pricing$q$, $q$annual$q$, NULL, $q$["Compliance automation templates","Workforce identity and SSO","Windows and Android management"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Kandji is a cloud-based device management and security platform originally built exclusively for Apple hardware. Founded in 2018 in San Diego by Adam Pettit, Wesley Pettit, and Mark Daughters, it grew into one of the most well-funded companies in the enterprise Apple management space, raising over 288 million dollars across five funding rounds including a 2024 Series D led by General Catalyst.$q$, $q$Starting in late 2025, the company began transitioning its brand to Iru, reflecting an expanded mission that goes beyond Apple-only MDM to cover Windows and Android device management alongside identity, endpoint detection and response, vulnerability management, and compliance automation. Existing Kandji customers and product names are being migrated to Iru branding, though the underlying platform functionality carries over unchanged.$q$, $q$The platform is aimed squarely at IT and security teams that need to enroll, configure, secure, and prove compliance for corporate device fleets without heavy manual scripting, positioning it against legacy MDM vendors that were not built with Apple's zero-touch deployment model in mind.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Kandji's core MDM features include zero-touch enrollment via Apple's Automated Device Enrollment, Blueprints for reusable configuration templates, a Self Service catalog that lets employees install pre-approved apps without IT intervention, and Liftoff for branded onboarding flows on new devices.$q$, $q$On the security side, Kandji offers native EDR for macOS threat detection, continuous vulnerability management with CVE monitoring, and Prism for real-time visibility into installed apps, OS versions, and configuration drift across the fleet. Compliance templates are pre-mapped to frameworks such as SOC 2, HIPAA, ISO 27001, and CIS benchmarks, generating audit-ready evidence automatically.$q$, $q$Under the Iru rebrand, the platform is expanding to include Workforce Identity for passwordless single sign-on, plus Windows and Android endpoint management, positioning it as a single console for identity, device management, and security rather than an Apple-only point solution.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Kandji (now transitioning to Iru) does not publish standard pricing on its website; prospective customers must request a custom quote based on device count, product modules selected (MDM, EDR, vulnerability management, compliance), and contract length. Contracts are typically annual, billed yearly, and non-cancellable mid-term.$q$, $q$Third-party estimates and reseller quotes suggest per-device pricing in the range of roughly 3 to 15 dollars per device per month depending on bundle, with some deployments requiring a practical minimum of around 25 devices. Organizations evaluating the platform should expect a sales-led buying process rather than self-serve checkout.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
