INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('298368f7-68f8-4264-b78c-a684a417a0b3', $q$Automatic and manual issue searching$q$, $q$Finds available comic issue downloads across configured indexers, either automatically on a schedule or on demand.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('298368f7-68f8-4264-b78c-a684a417a0b3', $q$ComicVine metadata matching$q$, $q$Identifies series, publishers, and issue numbers accurately using ComicVine as a metadata source.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('298368f7-68f8-4264-b78c-a684a417a0b3', $q$Multi-format library support$q$, $q$Handles single issues, trade paperbacks, one-shots, and hardcovers within one organized library.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('298368f7-68f8-4264-b78c-a684a417a0b3', $q$Automated file renaming and organization$q$, $q$Renames, converts, and moves downloaded files into a clean, consistent folder structure automatically.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('298368f7-68f8-4264-b78c-a684a417a0b3', $q$Komga and Kavita integration$q$, $q$Works alongside popular self-hosted comic reader servers so acquisition and reading stay decoupled but connected.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('298368f7-68f8-4264-b78c-a684a417a0b3', $q$Docker-first deployment$q$, $q$Ships as an official Docker image for quick setup on NAS devices, home servers, or homelab stacks.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('298368f7-68f8-4264-b78c-a684a417a0b3', $q$Download client integration$q$, $q$Connects to standard download clients used throughout the *arr ecosystem to automate the fetch step.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('298368f7-68f8-4264-b78c-a684a417a0b3', $q$REST API$q$, $q$Provides programmatic access for scripting, automation, and integration with other self-hosted tools.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('298368f7-68f8-4264-b78c-a684a417a0b3', $q$Completely free and open source with an active GPL-3.0 codebase$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('298368f7-68f8-4264-b78c-a684a417a0b3', $q$Familiar Sonarr/Radarr-style interface for anyone already running an *arr stack$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('298368f7-68f8-4264-b78c-a684a417a0b3', $q$Automates the full pipeline from search to organized, renamed library files$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('298368f7-68f8-4264-b78c-a684a417a0b3', $q$Integrates cleanly with modern comic readers like Komga and Kavita$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('298368f7-68f8-4264-b78c-a684a417a0b3', $q$Actively maintained with regular releases and a responsive Discord community$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('298368f7-68f8-4264-b78c-a684a417a0b3', $q$Requires self-hosting knowledge, Docker, and comfort with the *arr ecosystem$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('298368f7-68f8-4264-b78c-a684a417a0b3', $q$No official managed cloud version directly from the developer$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('298368f7-68f8-4264-b78c-a684a417a0b3', $q$Relies on ComicVine and third-party indexers, which can vary in coverage and reliability$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('298368f7-68f8-4264-b78c-a684a417a0b3', $q$Smaller community and fewer guides compared to more established *arr tools$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('298368f7-68f8-4264-b78c-a684a417a0b3', $q$No dedicated mobile app; management happens through the web dashboard$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('298368f7-68f8-4264-b78c-a684a417a0b3', $q$Is Kapowarr free to use?$q$, $q$Yes. Kapowarr is fully open source under the GPL-3.0 license with no paid tiers or feature restrictions; the developer accepts optional donations via Ko-fi.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('298368f7-68f8-4264-b78c-a684a417a0b3', $q$What is the *arr suite Kapowarr belongs to?$q$, $q$The *arr suite refers to a family of self-hosted media automation tools like Sonarr (TV), Radarr (movies), and Lidarr (music). Kapowarr applies the same search-download-organize workflow to comic books.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('298368f7-68f8-4264-b78c-a684a417a0b3', $q$Does Kapowarr work with Komga or Kavita?$q$, $q$Yes. Kapowarr focuses on acquiring and organizing comics, and it is commonly paired with reader servers such as Komga or Kavita for browsing and reading the resulting library.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('298368f7-68f8-4264-b78c-a684a417a0b3', $q$How do I install Kapowarr?$q$, $q$The recommended method is Docker, using the official image published on the project's GitHub repository. A manual Python installation is also supported for users who prefer running it directly on a host machine.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('298368f7-68f8-4264-b78c-a684a417a0b3', $q$Where does Kapowarr get comic metadata?$q$, $q$Kapowarr primarily uses ComicVine to match and identify volumes, issues, and publishers for accurate library organization.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('298368f7-68f8-4264-b78c-a684a417a0b3', $q$Is there a hosted version of Kapowarr if I do not want to self-host?$q$, $q$Kapowarr itself is self-hosted only, but third-party managed hosting providers such as ElfHosted sell pre-configured Kapowarr instances, often bundled with a comic reader like Komga or Kavita.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('298368f7-68f8-4264-b78c-a684a417a0b3', $q$Automating a home comic library$q$, $q$A collector connects Kapowarr to their indexers and download client so new issues of tracked series are found, downloaded, and organized automatically.$q$, $q$Home comic collectors and homelab users$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('298368f7-68f8-4264-b78c-a684a417a0b3', $q$Modernizing an existing Mylar setup$q$, $q$A self-hoster migrates from an older comic automation tool to Kapowarr for a more modern interface and active development.$q$, $q$Existing self-hosted *arr stack operators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('298368f7-68f8-4264-b78c-a684a417a0b3', $q$Pairing acquisition with a reading server$q$, $q$A user runs Kapowarr alongside Komga or Kavita so downloading and renaming comics feeds directly into a browsable reading library.$q$, $q$Self-hosted media server administrators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('298368f7-68f8-4264-b78c-a684a417a0b3', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full GPL-3.0 source code","Unlimited library size","Docker and manual install options","REST API access","Community Discord support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('298368f7-68f8-4264-b78c-a684a417a0b3', $q$Managed Hosting (ElfHosted, third-party)$q$, $q$Custom pricing$q$, $q$monthly$q$, NULL, $q$["Pre-configured hosted instance","Optional Komga or Kavita bundle","Provider-managed uptime and updates"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('298368f7-68f8-4264-b78c-a684a417a0b3', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Kapowarr is a self-hosted, open-source application that automates the collection, organization, and file management of digital comic books. It follows the same design philosophy as the well-known *arr media automation tools, such as Sonarr and Radarr, applying the same search-download-rename-organize workflow to comic volumes and issues instead of TV shows or movies.$q$, $q$The project is maintained by a developer under the GitHub handle Casvt and is released under the GPL-3.0 open-source license with no company or commercial tier behind it. It runs as a Docker container or manual Python install, making it a natural addition to existing home-lab and self-hosted media server stacks.$q$, $q$Kapowarr matches comics against metadata providers like ComicVine to correctly identify series, issue numbers, and publishers before searching indexers and download clients for available files, then renames and moves the results into an organized library folder structure ready for reading apps like Komga or Kavita.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('298368f7-68f8-4264-b78c-a684a417a0b3', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core functionality includes automatic and manual issue searching, metadata matching via ComicVine, and support for single issues, trade paperbacks, one-shots, and hardcovers. Once a match is found, Kapowarr automates the full pipeline from download client handoff to renaming, format conversion, and moving files into a consistent folder structure.$q$, $q$The web-based dashboard mirrors the familiar Sonarr/Radarr layout, covering media management settings, download client configuration, metadata preferences, and general application options, all accessible without needing to touch configuration files directly.$q$, $q$Kapowarr integrates with popular self-hosted comic readers such as Komga and Kavita, and exposes a REST API for scripting and third-party integration, letting advanced users tie it into broader home automation and media-management workflows.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('298368f7-68f8-4264-b78c-a684a417a0b3', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Kapowarr is completely free and open source, with no paid tier, license key, or feature restrictions of any kind. The full source code is available on GitHub, and the project accepts voluntary donations through Ko-fi to support ongoing development.$q$, $q$Users who prefer not to self-host can use a managed provider such as ElfHosted, which sells pre-configured Kapowarr instances (often bundled with Komga or Kavita) for a monthly hosting fee, though the underlying Kapowarr software itself remains free regardless of how it is deployed.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('298368f7-68f8-4264-b78c-a684a417a0b3', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
