INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('298368f7-68f8-4264-b78c-a684a417a0b3', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Browser-based collaborative editor$q$, $q$Multiple users can edit the same video project in real time entirely from a web browser.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$AI subtitles and translation$q$, $q$Automatically generates and translates captions across dozens of languages.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$AI voice cloning and text-to-speech$q$, $q$Creates custom synthetic voices and converts text scripts directly into narration.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Automated dubbing$q$, $q$Translates and dubs videos into multiple languages using AI-generated voiceovers.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Smart Cut$q$, $q$Automatically detects and trims silence or dead air from raw footage.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Brand Kit$q$, $q$Stores brand fonts, colors, and logos for consistent output across a team's content.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Templates for social formats$q$, $q$Pre-built layouts optimized for YouTube, Instagram Stories, TikTok, and memes.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Built-in screen recorder$q$, $q$Captures screen footage directly in the browser without third-party recording software.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$No software installation required; runs fully in the browser$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Real-time multi-user collaboration similar to Google Docs for video$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Deep, constantly expanding AI toolset for subtitles, dubbing, and voice cloning$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Generous free plan for quick, low-stakes edits$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Templates and Brand Kit speed up repetitive social content production$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Free plan exports carry a visible watermark$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$AI features are metered by monthly credits that can run out on heavier workloads$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Browser-based rendering can be slower than local desktop editing for complex projects$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Higher tiers (Business, Enterprise) get expensive for small teams needing advanced AI features$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Less granular manual control than professional desktop NLEs like Premiere Pro$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Is Kapwing free to use?$q$, $q$Yes, Kapwing has a free plan with unlimited exports, though free exports include a watermark and are capped at one minute in length and 720p resolution.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Who founded Kapwing?$q$, $q$Kapwing was founded in 2017 by Julia Enthoven and Eric Lu, both former Google product managers, in San Francisco, California.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Does Kapwing use AI credits?$q$, $q$Yes, AI-powered features like subtitle generation, text-to-speech, voice cloning, and dubbing consume monthly credits that vary by plan, from 10 credits on the Free plan up to 4,000 on Business.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Can teams collaborate on the same video in Kapwing?$q$, $q$Yes, Kapwing supports real-time collaborative editing where multiple users can work on the same project simultaneously in the browser.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$What is Kapwing's closest competitor?$q$, $q$CapCut, Veed.io, Descript, and Canva's video tools are the most commonly cited alternatives, with Kapwing differentiated by its collaborative browser workflow and deep AI feature set.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Does Kapwing support 4K export?$q$, $q$4K export is available starting on the Pro plan; the Free plan is limited to 720p resolution.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Social media content production$q$, $q$Marketing teams use Kapwing's templates and AI subtitle tools to quickly produce short-form videos for TikTok, Instagram, and YouTube.$q$, $q$Social media managers and marketing teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Multi-language content localization$q$, $q$Creators use AI dubbing and translation to repurpose a single video into multiple language versions without hiring voice actors.$q$, $q$International content creators and localization teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Collaborative team video editing$q$, $q$Distributed teams co-edit training or promotional videos in real time from the browser without exchanging large project files.$q$, $q$Remote and distributed content teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Unlimited exports with watermark","Videos up to 1 minute at 720p","10 AI credits per month"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Pro$q$, $q$$16/month (billed annually) or $24/month (monthly)$q$, $q$monthly or annual$q$, NULL, $q$["No watermark","4K export and 6GB uploads","Projects up to 2 hours","Brand Kit and 100GB storage","1,000 AI credits per month"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Business$q$, $q$$50/month (billed annually) or $64/month (monthly)$q$, $q$monthly or annual$q$, NULL, $q$["Everything in Pro","Custom voice cloning and lip sync","500GB storage","4,000 AI credits per month"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$Enterprise$q$, $q$Custom pricing$q$, $q$annual$q$, NULL, $q$["Custom billing and credit limits","Dedicated account manager","SAML SSO","Custom cloud storage","Onboarding and training"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Kapwing is a browser-based video and content creation platform founded in San Francisco in 2017 by Julia Enthoven and Eric Lu, both former Google product managers. It was built as a simpler, faster, and more collaborative alternative to desktop editors like Adobe Premiere and Final Cut, aimed at creators producing short-form content for YouTube, Instagram, and TikTok.$q$, $q$The company raised an 11 million dollar Series A led by CRV in 2018 and has since grown to serve more than 100,000 customers and over 10 million dollars in annual revenue as of 2024, with a lean team of roughly 11 to 50 employees. All editing happens in the browser on Kapwing's cloud infrastructure, enabling real-time collaborative editing across multiple users on the same project.$q$, $q$Over time Kapwing has layered a substantial AI feature set onto its core video editor, including automatic subtitling, text-to-speech, voice cloning, and automated dubbing, positioning it as much as an AI content-generation tool as a traditional cut-and-trim editor.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At its core, Kapwing offers a full browser-based non-linear video editor with trimming, layering, transitions, text overlays, and templates optimized for social formats. A Smart Cut feature automatically removes silence and dead air, and a built-in screen recorder captures footage directly in the browser.$q$, $q$The AI toolset includes automatic subtitle generation with multi-language translation, AI text-to-speech, custom voice cloning, and automated video dubbing, alongside an AI meme generator and background removal. These AI features consume a monthly credit allowance that scales with the pricing tier.$q$, $q$For teams, Kapwing provides a collaborative workspace where multiple editors can work on the same project simultaneously, plus a Brand Kit for consistent fonts, colors, and logos across content, and higher tiers add SAML SSO and dedicated account management for larger organizations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Kapwing uses a freemium, credit-based pricing model. The Free plan supports unlimited watermarked exports at up to 720p for videos under one minute with 10 monthly AI credits, while the Pro plan (16 dollars per month billed annually, or 24 dollars billed monthly) removes the watermark, enables 4K export and 6GB uploads, and includes 1,000 monthly credits plus 100GB of storage.$q$, $q$The Business plan (50 dollars per month billed annually, or 64 dollars billed monthly) adds custom voice cloning, lip sync, 500GB of storage, and 4,000 monthly credits, while Enterprise pricing is custom and includes SAML SSO, dedicated support, and custom cloud storage limits for larger teams.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
