INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('27a0d263-d000-4bfb-ac14-1b67221d0428', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fab34bce-400c-45a0-b3be-67931923345e', $q$AI-powered auto-tagging$q$, $q$Automatically tags saved content using cloud AI providers or fully local models via Ollama.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fab34bce-400c-45a0-b3be-67931923345e', $q$Full-text search$q$, $q$Search across every saved bookmark, note, image, and highlight to instantly find past content.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fab34bce-400c-45a0-b3be-67931923345e', $q$Rule engine automation$q$, $q$Custom rules trigger actions like tagging or archiving based on conditions you define.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fab34bce-400c-45a0-b3be-67931923345e', $q$RSS feed auto-import$q$, $q$Automatically pulls in new articles from subscribed RSS feeds without manual saving.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fab34bce-400c-45a0-b3be-67931923345e', $q$Highlights capture$q$, $q$Save and organize specific text passages highlighted from articles and pages.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fab34bce-400c-45a0-b3be-67931923345e', $q$Cross-platform clients$q$, $q$Native iOS and Android apps plus Chrome, Firefox, and Safari browser extensions.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fab34bce-400c-45a0-b3be-67931923345e', $q$Collaborative shared lists$q$, $q$Share curated bookmark lists with teams, family, or collaborators.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fab34bce-400c-45a0-b3be-67931923345e', $q$REST API and webhooks$q$, $q$Integrate Karakeep with other tools and automation workflows programmatically.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fab34bce-400c-45a0-b3be-67931923345e', $q$Self-hosted version is completely free forever with full feature parity$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fab34bce-400c-45a0-b3be-67931923345e', $q$AI tagging can run entirely locally via Ollama for full data privacy$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fab34bce-400c-45a0-b3be-67931923345e', $q$Broad platform support including native mobile apps and browser extensions$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fab34bce-400c-45a0-b3be-67931923345e', $q$Active open-source community with frequent updates and over 26,000 GitHub stars$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fab34bce-400c-45a0-b3be-67931923345e', $q$Handles more than just links: notes, images, PDFs, and highlights in one place$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fab34bce-400c-45a0-b3be-67931923345e', $q$Cloud free tier is very limited (around 10 bookmarks and 20MB storage)$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fab34bce-400c-45a0-b3be-67931923345e', $q$Self-hosting requires Docker and basic server administration knowledge$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fab34bce-400c-45a0-b3be-67931923345e', $q$Cloud service is still in public beta, so reliability guarantees are limited$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fab34bce-400c-45a0-b3be-67931923345e', $q$AI tagging quality depends on which model or provider is configured$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fab34bce-400c-45a0-b3be-67931923345e', $q$Smaller ecosystem and fewer third-party integrations than long-established read-it-later apps$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fab34bce-400c-45a0-b3be-67931923345e', $q$Is Karakeep the same as Hoarder?$q$, $q$Yes. Karakeep was originally launched as Hoarder in January 2023 and rebranded to Karakeep in 2025. The underlying project and features carried over under the new name.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fab34bce-400c-45a0-b3be-67931923345e', $q$Is Karakeep free?$q$, $q$The self-hosted version is free forever with full features. The managed cloud version offers a limited free tier plus a Pro plan at 4 dollars per month or 40 dollars per year.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fab34bce-400c-45a0-b3be-67931923345e', $q$Can Karakeep's AI tagging run without sending data to the cloud?$q$, $q$Yes. Karakeep supports local AI models via Ollama, so users who self-host can keep all AI tagging processing entirely on their own hardware.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fab34bce-400c-45a0-b3be-67931923345e', $q$Who created Karakeep?$q$, $q$Karakeep was created by developer Mohamed Bassem and is now maintained by Localhost Labs Ltd as an open-source AGPL-3.0 project.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fab34bce-400c-45a0-b3be-67931923345e', $q$Does Karakeep have mobile apps?$q$, $q$Yes, Karakeep offers native iOS and Android apps as well as browser extensions for Chrome, Firefox, and Safari.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fab34bce-400c-45a0-b3be-67931923345e', $q$What can I save in Karakeep besides links?$q$, $q$Karakeep supports bookmarking links, taking notes, storing images and PDFs, and capturing highlighted text passages from saved articles.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fab34bce-400c-45a0-b3be-67931923345e', $q$Self-hosted research knowledge base$q$, $q$A researcher self-hosts Karakeep on a home server to save articles, PDFs, and highlights with full-text search, keeping all data under their own control.$q$, $q$Researchers and privacy-conscious power users$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fab34bce-400c-45a0-b3be-67931923345e', $q$Replacing a discontinued read-it-later app$q$, $q$A former Pocket or Omnivore user migrates to Karakeep's managed cloud service for a similar save-and-read experience with AI tagging.$q$, $q$Former Pocket and Omnivore users$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fab34bce-400c-45a0-b3be-67931923345e', $q$Team knowledge sharing$q$, $q$A small team uses Karakeep's collaborative shared lists to curate and distribute research links and reference material.$q$, $q$Small teams and knowledge workers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fab34bce-400c-45a0-b3be-67931923345e', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full feature parity with paid cloud tiers","Docker deployment","Local AI tagging via Ollama","Unlimited bookmarks, notes, and storage limited only by your server"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fab34bce-400c-45a0-b3be-67931923345e', $q$Cloud Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Around 10 bookmarks","20MB storage","Trial access to Karakeep Cloud"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fab34bce-400c-45a0-b3be-67931923345e', $q$Cloud Pro$q$, $q$$4/month or $40/year$q$, $q$monthly or annual$q$, NULL, $q$["Unlimited bookmarks","AI auto-tagging","Full-text search","50GB storage"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fab34bce-400c-45a0-b3be-67931923345e', $q$Corporate$q$, $q$Custom pricing$q$, $q$annual$q$, NULL, $q$["Custom per-seat pricing","Single sign-on (SSO)","Priority support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fab34bce-400c-45a0-b3be-67931923345e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Karakeep is an open-source, self-hostable app for saving and organizing bookmarks, notes, images, and PDFs, with AI automatically tagging everything for faster retrieval. Created by developer Mohamed Bassem, it launched in January 2023 as Hoarder before rebranding to Karakeep in 2025, and is now maintained by Localhost Labs Ltd under the AGPL-3.0 license.$q$, $q$The project has become one of the most popular self-hosted bookmarking tools, with more than 26,000 GitHub stars and over 150 contributors. It can be deployed via Docker for full self-hosting, or accessed through an official managed cloud service currently in public beta for users who prefer not to run their own infrastructure.$q$, $q$A defining feature is flexible AI tagging: users can route auto-tagging through a cloud provider like OpenAI, or run it entirely locally via Ollama for privacy-focused, offline-capable operation. This makes Karakeep appealing both to casual users who want convenience and to privacy-conscious self-hosters who want zero third-party data exposure.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fab34bce-400c-45a0-b3be-67931923345e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Karakeep saves links, notes, images, and PDFs into one searchable library, with automatic metadata fetching for titles, descriptions, and preview images, and full-text search across everything saved. AI-based auto-tagging categorizes content automatically, while a rule engine lets users define custom automation, such as tagging or archiving items based on specific conditions.$q$, $q$Additional organization tools include highlight capture for saving specific passages from articles, collaborative shared lists, RSS feed auto-import for continuous content collection, and bulk actions for managing large numbers of bookmarks at once.$q$, $q$Client coverage is broad: native iOS and Android apps, browser extensions for Chrome, Firefox, and Safari, a web app, a command-line interface, and a REST API with webhook support for integrating Karakeep into other tools and automation pipelines.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fab34bce-400c-45a0-b3be-67931923345e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The self-hosted version of Karakeep is completely free forever with full feature parity to the paid cloud tiers, since anyone willing to run their own Docker instance gets the entire feature set at no cost. This is the primary draw for the open-source, self-hosting audience.$q$, $q$For users who prefer a managed experience, Karakeep Cloud offers a limited Free tier (around 10 bookmarks, 20MB storage) as a trial, a Pro tier at 4 dollars per month or 40 dollars per year with unlimited bookmarks, AI tagging, full-text search, and 50GB storage, and a Corporate tier with custom per-seat pricing, SSO, and priority support.$q$]::text[], 2);
