INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5019ca62-2bfd-4c78-a7e8-0c678cbbaa68', $q$LinkedIn Chrome extension enrichment$q$, $q$Reveals verified emails and phone numbers directly on LinkedIn, Sales Navigator, and Recruiter profiles.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5019ca62-2bfd-4c78-a7e8-0c678cbbaa68', $q$Verified direct-dial phone numbers$q$, $q$Surfaces mobile and direct-dial numbers alongside email addresses for faster outbound calling.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5019ca62-2bfd-4c78-a7e8-0c678cbbaa68', $q$CRM integrations$q$, $q$Native connections to Salesforce, HubSpot, and Pipedrive for pushing enriched contacts directly into pipelines.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5019ca62-2bfd-4c78-a7e8-0c678cbbaa68', $q$Zapier connectivity$q$, $q$Automates contact enrichment workflows across hundreds of other tools via Zapier.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5019ca62-2bfd-4c78-a7e8-0c678cbbaa68', $q$Bulk list building$q$, $q$Enriches larger prospect lists at scale rather than one LinkedIn profile at a time.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5019ca62-2bfd-4c78-a7e8-0c678cbbaa68', $q$REST API access$q$, $q$Lets developers enrich contact data programmatically outside the browser extension.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5019ca62-2bfd-4c78-a7e8-0c678cbbaa68', $q$GDPR and CCPA compliant data sourcing$q$, $q$Data collection and storage practices are built around European and California privacy regulations.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5019ca62-2bfd-4c78-a7e8-0c678cbbaa68', $q$Intent data (Enterprise)$q$, $q$Enterprise customers gain access to buyer intent signals layered on top of contact enrichment.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5019ca62-2bfd-4c78-a7e8-0c678cbbaa68', $q$Genuinely usable free plan with real monthly credits$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5019ca62-2bfd-4c78-a7e8-0c678cbbaa68', $q$Fast, in-context enrichment directly on LinkedIn profiles$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5019ca62-2bfd-4c78-a7e8-0c678cbbaa68', $q$Strong GDPR compliance and European contact data coverage$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5019ca62-2bfd-4c78-a7e8-0c678cbbaa68', $q$Pricing undercuts most full-scale sales-intelligence platforms$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5019ca62-2bfd-4c78-a7e8-0c678cbbaa68', $q$Backed by Cognism's larger data infrastructure since its 2022 acquisition$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5019ca62-2bfd-4c78-a7e8-0c678cbbaa68', $q$Phone number and direct-dial coverage can vary significantly outside Europe$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5019ca62-2bfd-4c78-a7e8-0c678cbbaa68', $q$Credit-based pricing can feel restrictive for high-volume prospectors on lower tiers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5019ca62-2bfd-4c78-a7e8-0c678cbbaa68', $q$Full API access and unlimited phone credits are locked behind the Business tier$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5019ca62-2bfd-4c78-a7e8-0c678cbbaa68', $q$Some advanced features overlap with parent company Cognism, creating potential upsell pressure$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5019ca62-2bfd-4c78-a7e8-0c678cbbaa68', $q$Primarily optimized for LinkedIn workflows, less useful for prospecting outside LinkedIn$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5019ca62-2bfd-4c78-a7e8-0c678cbbaa68', $q$Is Kaspr free to use?$q$, $q$Yes, Kaspr has a free plan with 15 B2B email credits, 5 phone credits, and 5 direct email credits per month, along with basic Chrome extension access.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5019ca62-2bfd-4c78-a7e8-0c678cbbaa68', $q$Who owns Kaspr?$q$, $q$Kaspr was founded independently in Paris in 2018 by Allan Benguigui and Omar Ghorbel, and was acquired by UK-based sales intelligence company Cognism in April 2022.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5019ca62-2bfd-4c78-a7e8-0c678cbbaa68', $q$How does Kaspr find phone numbers and emails?$q$, $q$Kaspr's Chrome extension overlays LinkedIn, Sales Navigator, and Recruiter profiles and pulls verified contact data from its own database and partner data sources.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5019ca62-2bfd-4c78-a7e8-0c678cbbaa68', $q$Does Kaspr integrate with my CRM?$q$, $q$Yes, Kaspr has native integrations with Salesforce, HubSpot, and Pipedrive, plus a Zapier connector and a REST API for custom integrations.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5019ca62-2bfd-4c78-a7e8-0c678cbbaa68', $q$Is Kaspr GDPR compliant?$q$, $q$Yes, Kaspr emphasizes GDPR and CCPA-compliant data sourcing and storage throughout its pipeline, which is a key differentiator for European sales teams.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5019ca62-2bfd-4c78-a7e8-0c678cbbaa68', $q$What is the difference between Kaspr and Cognism?$q$, $q$Kaspr is a lightweight, self-serve LinkedIn prospecting tool owned by Cognism, while Cognism is the larger parent sales-intelligence platform sold separately at higher, enterprise-level price points with more extensive data and intent features.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5019ca62-2bfd-4c78-a7e8-0c678cbbaa68', $q$LinkedIn-based outbound prospecting$q$, $q$SDRs use the Kaspr Chrome extension to pull verified emails and phone numbers while browsing LinkedIn and Sales Navigator, feeding leads straight into outreach sequences.$q$, $q$Sales development reps (SDRs)$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5019ca62-2bfd-4c78-a7e8-0c678cbbaa68', $q$Recruiter candidate sourcing$q$, $q$Recruiters use Kaspr with LinkedIn Recruiter to find direct contact details for passive candidates without leaving LinkedIn.$q$, $q$Recruiters and talent acquisition teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5019ca62-2bfd-4c78-a7e8-0c678cbbaa68', $q$GDPR-sensitive European sales prospecting$q$, $q$European sales teams use Kaspr for its GDPR-compliant data sourcing when building outbound lists that must meet strict regional privacy requirements.$q$, $q$European B2B sales teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5019ca62-2bfd-4c78-a7e8-0c678cbbaa68', $q$Free$q$, $q$$0/month$q$, $q$monthly$q$, NULL, $q$["15 B2B email credits/month","5 phone credits/month","5 direct email credits/month","Chrome extension access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5019ca62-2bfd-4c78-a7e8-0c678cbbaa68', $q$Starter$q$, $q$Around $49/month$q$, $q$monthly or annual$q$, NULL, $q$["Unlimited B2B email credits","Up to 1,200 phone credits/year","Sales Navigator integration","Zapier connectivity"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5019ca62-2bfd-4c78-a7e8-0c678cbbaa68', $q$Business$q$, $q$Around $79 to $99/month$q$, $q$monthly or annual$q$, NULL, $q$["Unlimited phone credits","Up to 2,400 direct email credits/year","LinkedIn Recruiter Lite integration","Full API access"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5019ca62-2bfd-4c78-a7e8-0c678cbbaa68', $q$Enterprise$q$, $q$Custom pricing$q$, $q$annual$q$, NULL, $q$["Unlimited credits","Intent data","Advanced Salesforce enrichment","Single sign-on (SSO)"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5019ca62-2bfd-4c78-a7e8-0c678cbbaa68', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Kaspr is a B2B contact enrichment and LinkedIn prospecting tool built around a Chrome extension that reveals verified email addresses and phone numbers directly on LinkedIn, Sales Navigator, and Recruiter profiles. It was founded in Paris in 2018 by CEO Allan Benguigui and CTO Omar Ghorbel to serve European sales teams with GDPR-compliant contact data.$q$, $q$In April 2022, Kaspr was acquired by Cognism, a UK-based sales intelligence company, and now operates as part of the Cognism Group while keeping its own brand, product, and Paris headquarters. The acquisition combined Kaspr's self-serve, LinkedIn-native workflow with Cognism's larger contact database and compliance infrastructure.$q$, $q$Kaspr's core value proposition is speed: rather than requiring reps to leave LinkedIn and search a separate database, contact details surface directly in-context as an overlay while browsing profiles, which has made it popular with individual SDRs and small sales teams looking for a lightweight prospecting workflow.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5019ca62-2bfd-4c78-a7e8-0c678cbbaa68', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The Chrome extension enriches LinkedIn, Sales Navigator, and Recruiter profiles in real time with personal email, verified professional email, and direct-dial or mobile phone numbers, pulled from Kaspr's own database and partner data sources. Bulk list-building tools let users enrich larger prospect lists at scale rather than one profile at a time.$q$, $q$Native CRM integrations connect Kaspr to Salesforce, HubSpot, and Pipedrive, while a Zapier connector extends automation to hundreds of other tools, and a REST API is available for developers who want to enrich contacts programmatically outside the browser.$q$, $q$Kaspr emphasizes GDPR and CCPA-compliant data sourcing and storage throughout its pipeline, and higher tiers add intent data, custom member permissions, LinkedIn Recruiter Lite integration, and advanced Salesforce enrichment for larger sales organizations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5019ca62-2bfd-4c78-a7e8-0c678cbbaa68', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Kaspr's Free plan includes 15 B2B email credits, 5 phone credits, and 5 direct email credits per month with basic Chrome extension access. The Starter plan runs roughly 49 dollars per month with unlimited B2B email credits, up to 1,200 phone credits per year, and Sales Navigator integration, while annual billing brings the effective rate down.$q$, $q$The Business plan, priced roughly between 79 and 99 dollars per month, adds unlimited phone credits, LinkedIn Recruiter Lite integration, and full API access, and is marketed as Kaspr's best-value tier. An Enterprise tier offers custom pricing with unlimited credits, intent data, and SSO for larger teams, typically sold through Cognism's enterprise sales process.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5019ca62-2bfd-4c78-a7e8-0c678cbbaa68', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
