-- Enrichment marathon batch: Kanboard, Kandji, Kapowarr, Kapwing, Karakeep, Karaoke Eternal, Kasm Workspaces, Kaspr

-- ── Kanboard ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Free, open-source, self-hosted Kanban board for visualizing and automating task workflows with minimal setup.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Kanboard Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Kanboard is a free, self-hosted, open-source Kanban board for developers and small teams. See features, pricing, pros, cons, and alternatives for 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Kanboard is a free and open-source, self-hosted Kanban project management application built in PHP that lets individuals and small teams visualize and automate their workflow on a simple drag-and-drop board. The project was created by French developer Frederic Guillot and first released in 2014; it is distributed under the permissive MIT License and hosted publicly on GitHub, where more than 330 contributors have submitted code over the project's lifetime. Kanboard has no founding company, no venture funding, and no corporate headquarters in the traditional sense; it is a community-maintained open-source tool that anyone can download, install on their own server, and run at zero cost, which is why its pricing model is Open Source rather than a commercial SaaS tier. Architecturally, Kanboard runs on a standard PHP/Apache or PHP/Nginx stack, uses SQLite as its default embedded database for zero-configuration installs, and also supports MySQL and PostgreSQL for larger multi-user deployments. Official Docker images make self-hosting straightforward on a VPS, NAS, or home server, and third-party hosts such as Elestio and Stellar Hosted sell managed Kanboard hosting starting around 14 dollars per month for teams that do not want to run their own infrastructure. The core feature set is deliberately minimal: a single kanban board per project with configurable columns, work-in-progress (WIP) limits that visually flag overloaded columns, drag-and-drop task movement, subtasks, file attachments, Markdown-formatted comments and descriptions, task duplication and cross-project moves, recurring tasks, time tracking, and a query-language search and filter bar that can filter by assignee, category, due date, color, or status. Automation is handled through built-in automatic actions that trigger on events, such as moving a task, changing its color, or reassigning a user, without needing external workflow tools, and the app ships with public and private project boards, Gantt and calendar views, and CSV/iCal export. Authentication supports local accounts, LDAP/Active Directory, and OAuth2 providers including Google, GitHub, and GitLab, and the interface is translated into more than 30 languages. A REST/JSON-RPC API and a plugin architecture, with community plugins adding things like Slack notifications, webhooks, custom themes, and two-factor authentication, extend the base install without forking the core codebase. Because there is no paid tier, no usage limits, and no vendor lock-in, Kanboard's target audience is developers, sysadmins, and small technical teams who already self-host other infrastructure and want a lightweight, no-frills Kanban tool rather than a heavyweight project-management suite; it is frequently recommended in self-hosted and homelab communities alongside tools like Wekan, Focalboard, and Taiga. As of the mid-2020s the project entered what its maintainer describes as maintenance mode: new major features have slowed while community-contributed bug fixes and minor releases (the stable line reached 1.2.42 in November 2024) continue to ship regularly, meaning Kanboard is stable and production-ready but not aggressively evolving compared to venture-backed rivals. Its closest competitors are commercial SaaS Kanban tools such as Trello, Asana, and monday.com, plus other self-hosted alternatives like Wekan (also MIT-licensed, Node.js/MongoDB-based), Focalboard, and OpenProject. Kanboard differentiates itself from all of them by staying deliberately feature-light, running on cheap PHP hosting most developers already know how to operate, and never gating features behind a paywall since there is no company selling upgrades. For teams that value data ownership, low hosting cost, and simplicity over collaboration extras like real-time multi-cursor editing or built-in video calls, Kanboard remains one of the most durable and widely deployed open-source Kanban tools available.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'd35f0bfc-a880-4f59-aa8f-867b297a21c1';

