-- ── Kandji ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Apple-first device management (MDM) and security platform, now rebranding to Iru as it expands to Windows and Android.$q$, short_description),
  pricing_model = COALESCE($q$Enterprise$q$, pricing_model),
  starting_price = COALESCE($q$Custom pricing$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE($q$201-500 employees$q$, company_size),
  headquarters = COALESCE($q$San Diego, California, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Kandji Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Kandji is an Apple device management and security platform built for IT teams. See features, pricing, the Iru rebrand, pros, cons, and alternatives for 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Kandji is an Apple-first device management (MDM) and endpoint security platform built for IT and security teams that manage fleets of Mac, iPhone, and iPad devices at work. The company was founded in 2018 in San Diego, California, by Adam Pettit, Wesley Pettit, and Mark Daughters, and launched its commercial product in 2019 with a mission to make Apple deployment, configuration, and compliance dramatically simpler than legacy cross-platform MDM tools that treated Apple devices as an afterthought. Kandji raised a $3.375 million seed round led by First Round Capital, a $21 million Series A in 2020, a $60 million Series B in 2021, a $100 million Series C led by Tiger Global later in 2021, and a further $100 million Series D led by General Catalyst in July 2024, bringing total funding to more than 288 million dollars at a valuation of roughly 850 million dollars. In February 2025 the company opened a second headquarters in Coral Gables, Florida, alongside its original San Diego base. In late 2025 and through 2026, Kandji began rebranding as Iru, expanding beyond pure Apple MDM into a unified identity, endpoint management, endpoint detection and response (EDR), vulnerability management, and compliance automation platform that also covers Windows and Android devices; existing Kandji customers are being transitioned to the Iru platform, and product surfaces such as Kandji Self Service are being renamed to Iru Self Service, though functionality is carried over unchanged. Technically, Kandji operates as a cloud-based SaaS console that communicates with Apple's Device Enrollment Program (Automated Device Enrollment) and MDM protocol to provision devices out of the box with zero-touch deployment. Core features include Blueprints for templated device configuration profiles, a Self Service app catalog that lets end users install approved software without IT tickets, Liftoff for guided onboarding experiences, Prism for real-time fleet visibility and app/OS inventory, pre-built compliance templates mapped to frameworks like SOC 2, HIPAA, ISO 27001, and CIS benchmarks, and a native EDR product for macOS threat detection and response. It also offers Passport for passwordless identity and single sign-on, and vulnerability management for continuous CVE monitoring across the fleet. Pricing is not published; Kandji (Iru) sells through an annual, sales-assisted contract model, and third-party estimates place per-device costs in the range of roughly 3 to 15 dollars per device per month depending on the mix of MDM, EDR, and compliance modules purchased, with many resellers citing a practical minimum deployment size of around 25 devices. As of 2025-2026 the company reports roughly 201 to 500 employees and estimated annual recurring revenue in the tens of millions of dollars, reflecting rapid growth in the enterprise Apple management space. Kandji's target audience is IT administrators and security teams at mid-market and enterprise organizations, particularly Apple-heavy shops in tech, healthcare, and finance, that need automated compliance evidence and fast device provisioning at scale. Its primary named competitors are Jamf (the long-standing leader in Apple enterprise management), Addigy, Mosyle, Microsoft Intune (for mixed-fleet environments), and Fleet; Kandji differentiates itself with a more modern, DevOps-friendly UI, faster time-to-value for smaller IT teams, built-in compliance automation that reduces the need for separate GRC tooling, and, following the Iru rebrand, an expanded scope that no longer positions the product as Apple-only but as a broader unified endpoint and identity security platform.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '9de5de2c-21ac-48ff-89e4-3f7bf4c1ceb6';

