-- ── Karakeep ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open-source, self-hostable bookmark manager with AI auto-tagging, full-text search, and highlights, formerly Hoarder.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2023, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Karakeep Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Karakeep (formerly Hoarder) is an open-source bookmark manager with AI tagging and full-text search. See pricing, features, pros, cons for 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Karakeep is an open-source, self-hostable bookmark and knowledge-management application that lets users save links, notes, images, and PDFs into a single searchable library, with AI used to automatically tag and organize everything that gets saved. The project was created by developer Mohamed Bassem and originally launched in January 2023 under the name Hoarder; it was rebranded to Karakeep in 2025 to move away from the negative connotations of the word hoarder and to better reflect the product's broader scope beyond simple link-saving. The project is maintained by Localhost Labs Ltd and released under the AGPL-3.0 open-source license, with the codebase publicly available on GitHub where it has accumulated more than 26,000 stars and contributions from over 150 developers, making it one of the more popular self-hosted bookmarking tools in the homelab and open-source community. Architecturally, Karakeep is Docker-deployable for self-hosting, giving users complete control over their data, and it also offers an official managed cloud service (cloud.karakeep.app) currently in public beta for people who do not want to run their own server. On the AI side, automatic tagging can be powered either by a cloud AI provider such as OpenAI, or by locally hosted open-weight models via Ollama for users who want to keep all AI processing on their own hardware for privacy. Core features include full-text search across every saved bookmark, note, and highlight; automatic metadata fetching (titles, descriptions, and preview images) when a link is saved; a rule engine for custom automation, such as auto-tagging or auto-archiving based on conditions; RSS feed auto-import so new articles from subscribed feeds are captured automatically; collaborative shared lists for team or family use; highlight capture for saving specific passages of text from articles; bulk actions for managing many bookmarks at once; a REST API and webhook support for integrations; and a command-line interface for power users. Client support spans a web app, native iOS and Android mobile apps, and browser extensions for Chrome, Firefox, and Safari, with dark mode available across all surfaces. Pricing follows a freemium structure for the hosted cloud offering: a Free tier allows a small number of bookmarks (around 10) with 20MB of storage as a trial; the Pro tier costs 4 dollars per month or 40 dollars per year and unlocks unlimited bookmarks, AI tagging, full-text search, and 50GB of storage; and a Corporate tier offers custom per-seat pricing with single sign-on and priority support. Crucially, the self-hosted version remains completely free forever with full feature parity, since Karakeep's business model monetizes convenience (managed hosting) rather than gating features behind a paywall for people willing to run their own server. The tool's primary audience is privacy-conscious power users, researchers, and self-hosting enthusiasts who have outgrown browser bookmark bars or commercial read-it-later apps and want AI-assisted organization without surrendering their data to a third party. Its most commonly cited competitors and alternatives include Pocket (discontinued by Mozilla in 2025), Raindrop.io, Linkwarden, and Omnivore (also discontinued), with Karakeep differentiating itself through its combination of true self-hosting, AGPL open-source licensing, and AI-powered auto-tagging that works with either cloud or fully local models.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'fab34bce-400c-45a0-b3be-67931923345e';

