-- ── Kaspr ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$LinkedIn prospecting tool that finds verified B2B emails and phone numbers directly from LinkedIn profiles.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$Paris, France$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$Kaspr Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Kaspr is a LinkedIn prospecting tool for finding verified B2B emails and phone numbers. See pricing, features, pros, cons and alternatives for 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Kaspr is a B2B contact data and lead enrichment tool centered on a Chrome extension that finds verified email addresses and direct phone numbers for people directly from their LinkedIn profiles, LinkedIn Sales Navigator, and LinkedIn Recruiter searches. The company was founded in Paris, France, in 2018 by CEO Allan Benguigui and CTO Omar Ghorbel, who set out to fill a gap in the European sales-intelligence market for prospecting data with strong GDPR compliance and accurate coverage of contacts outside the US. In April 2022, Kaspr was acquired by Cognism, a UK-headquartered sales intelligence and B2B contact data company, for an undisclosed sum, and now operates as part of the Cognism Group while retaining its own product, brand, and Paris office; the acquisition gave Kaspr access to Cognism's broader data infrastructure and compliance operations while Cognism gained a strong self-serve, PLG-style entry point aimed at individual reps and small sales teams. Technically, Kaspr works primarily as a browser extension that overlays directly on LinkedIn and Sales Navigator pages, revealing enriched contact details (personal email, verified professional email, and mobile or direct-dial phone numbers) for the profile currently being viewed, with data pulled from Kaspr's own database plus network and partner sources; it also offers CRM integrations with Salesforce, HubSpot, and Pipedrive, a Zapier connector for broader automation, bulk list-building and enrichment for prospecting at scale, and a REST API for developers who want to enrich contacts programmatically outside the browser workflow. Kaspr emphasizes GDPR and CCPA compliance throughout its data-sourcing and storage processes, which is a key differentiator for European sales teams wary of contact databases with unclear data-privacy provenance. Pricing follows a freemium, credit-based model: the Free plan includes 15 B2B email credits, 5 phone credits, and 5 direct email credits per month with basic lead management and Chrome extension access; the Starter plan costs roughly 49 dollars per month (or a discounted annual rate around 45 euros per month) and includes unlimited B2B email credits, up to 1,200 phone credits per year, Sales Navigator integration, and Zapier connectivity; the Business plan, marked as Kaspr's best-value tier, costs roughly 79 to 99 dollars per month and adds unlimited phone credits, up to 2,400 direct email credits per year, LinkedIn Recruiter Lite integration, custom member permissions, and full API access; and an Enterprise tier offers custom pricing with unlimited credits, intent data, advanced Salesforce enrichment, and single sign-on for larger sales organizations, typically sold through Cognism's enterprise contracts at price points north of 1,500 dollars per seat per year. Kaspr's target audience is SDRs, account executives, and recruiters at small and mid-sized companies who prospect primarily through LinkedIn and need fast, in-context contact enrichment without switching to a separate sales-intelligence platform, as well as larger sales organizations that adopt Kaspr as an entry point before graduating to full Cognism contracts. Its most frequently cited competitors and alternatives include Apollo.io, Lusha, ZoomInfo, Cognism itself (its parent company, sold as a separate premium product), and Seamless.AI; Kaspr differentiates itself with a lightweight, LinkedIn-native workflow, a genuinely usable free tier, strong European/GDPR data compliance, and pricing that undercuts most enterprise sales-intelligence platforms while still offering an upgrade path into Cognism's larger data and intent-data ecosystem.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '5019ca62-2bfd-4c78-a7e8-0c678cbbaa68';

